function createAgent(overrides: Partial<AgentSummary>): AgentSummary {
  return {
    id: 'main',
    name: 'Main',
    persona: 'Coordinates the team',
    isDefault: false,
    model: 'openai/gpt-5.4',
    modelDisplay: 'GPT-5.4',
    inheritedModel: false,
    workspace: '~/.openclaw/workspace',
    agentDir: '~/.openclaw/agents/main/agent',
    mainSessionKey: 'agent:main:main',
    channelTypes: ['feishu'],
    avatar: null,
    teamRole: 'leader',
    chatAccess: 'direct',
    responsibility: 'Coordinate work',
    reportsTo: null,
    directReports: [],
    ...overrides,
  };
}

function getCard(name: string): HTMLElement {
  const heading = screen.getByText(name);
  const card = heading.closest('article');
  if (!card) {
    throw new Error(`Card not found for ${name}`);
  }
  return card;
}

describe('Employee Square card actions', () => {
  beforeEach(() => {
    vi.clearAllMocks();

    agentsStoreState.agents = [
      createAgent({ id: 'main', name: 'Main', mainSessionKey: 'agent:main:main' }),
      createAgent({
        id: 'researcher',
        name: 'Researcher',
        teamRole: 'worker',
        chatAccess: 'leader_only',
        mainSessionKey: 'agent:researcher:main',
      }),
    ];

    teamsStoreState.teams = [
      {
        id: 'team-alpha',
        name: 'Alpha Team',
        leaderId: 'main',
        memberIds: ['researcher'],
        description: '',
        status: 'active',
        createdAt: 1,
        updatedAt: 1,
        memberCount: 2,
        activeTaskCount: 1,
        lastActiveTime: undefined,
        leaderName: 'Main',
        memberAvatars: [],
      },
    ];

    chatStoreState.sessionLastActivity = {
      'agent:main:main': Date.now(),
      'agent:researcher:main': Date.now(),
    };
    chatStoreState.openDirectAgentSession.mockImplementation(() => 'agent:main:private-main');
  });

  it('launches direct chat and navigates to the unified chat surface', async () => {
    render(
      <MemoryRouter>
        <Agents />
      </MemoryRouter>,
    );

    await waitFor(() => {
      expect(agentsStoreState.fetchAgents).toHaveBeenCalled();
    });

    fireEvent.click(within(getCard('Main')).getByRole('button', { name: 'Chat' }));

    expect(chatStoreState.openDirectAgentSession).toHaveBeenCalledWith('main');
    expect(navigateMock).toHaveBeenCalledWith('/');
  });

  it('routes Memory and Details actions into the agent detail route', async () => {
    render(
      <MemoryRouter>
        <Agents />
      </MemoryRouter>,
    );

    await screen.findByText('Main');

    fireEvent.click(within(getCard('Main')).getByRole('button', { name: 'Memory' }));
    fireEvent.click(within(getCard('Main')).getByRole('button', { name: 'Details' }));

    expect(navigateMock).toHaveBeenNthCalledWith(1, '/agents/main?tab=memory');
    expect(navigateMock).toHaveBeenNthCalledWith(2, '/agents/main');
  });

  it('surfaces leader-only chat errors through a toast instead of routing', async () => {
    chatStoreState.openDirectAgentSession.mockImplementation(() => {
      throw new Error('Leader route required');
    });

    render(
      <MemoryRouter>
        <Agents />
      </MemoryRouter>,
    );

    await screen.findByText('Researcher');

    fireEvent.click(within(getCard('Researcher')).getByRole('button', { name: 'Chat' }));

    expect(toast.error).toHaveBeenCalledWith(expect.stringContaining('Leader route required'));
    expect(navigateMock).not.toHaveBeenCalledWith('/');
  });
});
import { access, mkdir, readFile, rm, writeFile } from 'fs/promises';
import { join } from 'path';
import { beforeEach, describe, expect, it, vi } from 'vitest';

const { testHome, testUserData } = vi.hoisted(() => {
  const suffix = Math.random().toString(36).slice(2);
  return {
    testHome: `/tmp/clawx-agent-config-${suffix}`,
    testUserData: `/tmp/clawx-agent-config-user-data-${suffix}`,
  };
});

vi.mock('os', async () => {
  const actual = await vi.importActual<typeof import('os')>('os');
  const mocked = {
    ...actual,
    homedir: () => testHome,
  };
  return {
    ...mocked,
    default: mocked,
  };
});

vi.mock('electron', () => ({
  app: {
    isPackaged: false,
    getPath: () => testUserData,
    getVersion: () => '0.0.0-test',
  },
}));

async function writeOpenClawJson(config: unknown): Promise<void> {
  const openclawDir = join(testHome, '.openclaw');
  await mkdir(openclawDir, { recursive: true });
  await writeFile(join(openclawDir, 'openclaw.json'), JSON.stringify(config, null, 2), 'utf8');
}

async function readOpenClawJson(): Promise<Record<string, unknown>> {
  const content = await readFile(join(testHome, '.openclaw', 'openclaw.json'), 'utf8');
  return JSON.parse(content) as Record<string, unknown>;
}

describe('agent config lifecycle', () => {
  beforeEach(async () => {
    vi.resetModules();
    vi.restoreAllMocks();
    await rm(testHome, { recursive: true, force: true });
    await rm(testUserData, { recursive: true, force: true });
  });

  it('lists configured agent ids from openclaw.json', async () => {
    await writeOpenClawJson({
      agents: {
        list: [
          { id: 'main', name: 'Main', default: true },
          { id: 'test3', name: 'test3' },
        ],
      },
    });

    const { listConfiguredAgentIds } = await import('@electron/utils/agent-config');

    await expect(listConfiguredAgentIds()).resolves.toEqual(['main', 'test3']);
  });

  it('falls back to the implicit main agent when no list exists', async () => {
    await writeOpenClawJson({});

    const { listConfiguredAgentIds } = await import('@electron/utils/agent-config');

    await expect(listConfiguredAgentIds()).resolves.toEqual(['main']);
  });

  it('includes canonical per-agent main session keys in the snapshot', async () => {
    await writeOpenClawJson({
      session: {
        mainKey: 'desk',
      },
      agents: {
        list: [
          { id: 'main', name: 'Main', default: true },
          { id: 'research', name: 'Research' },
        ],
      },
    });

    const { listAgentsSnapshot } = await import('@electron/utils/agent-config');

    const snapshot = await listAgentsSnapshot();
    expect(snapshot.agents).toEqual(
      expect.arrayContaining([
        expect.objectContaining({
          id: 'main',
          mainSessionKey: 'agent:main:desk',
          teamRole: 'leader',
          chatAccess: 'direct',
          responsibility: '',
        }),
        expect.objectContaining({
          id: 'research',
          mainSessionKey: 'agent:research:desk',
          teamRole: 'worker',
          chatAccess: 'direct',
          responsibility: '',
        }),
      ]),
    );
  });

  it('deletes the config entry and bindings for a removed agent, deferring destructive side effects', async () => {
    await writeOpenClawJson({
      agents: {
        defaults: {
          model: {
            primary: 'custom-custom27/MiniMax-M2.5',
            fallbacks: [],
          },
        },
        list: [
          {
            id: 'main',
            name: 'Main',
            default: true,
            workspace: '~/.openclaw/workspace',
            agentDir: '~/.openclaw/agents/main/agent',
          },
          {
            id: 'test2',
            name: 'test2',
            workspace: '~/.openclaw/workspace-test2',
            agentDir: '~/.openclaw/agents/test2/agent',
          },
          {
            id: 'test3',
            name: 'test3',
            workspace: '~/.openclaw/workspace-test3',
            agentDir: '~/.openclaw/agents/test3/agent',
          },
        ],
      },
      channels: {
        feishu: {
          enabled: true,
        },
      },
      bindings: [
        {
          agentId: 'test2',
          match: {
            channel: 'feishu',
          },
        },
      ],
    });

    const test2RuntimeDir = join(testHome, '.openclaw', 'agents', 'test2');
    const test2WorkspaceDir = join(testHome, '.openclaw', 'workspace-test2');
    await mkdir(join(test2RuntimeDir, 'agent'), { recursive: true });
    await mkdir(join(test2RuntimeDir, 'sessions'), { recursive: true });
    await mkdir(join(test2WorkspaceDir, '.openclaw'), { recursive: true });
    await writeFile(
      join(test2RuntimeDir, 'agent', 'auth-profiles.json'),
      JSON.stringify({ version: 1, profiles: {} }, null, 2),
      'utf8',
    );
    await writeFile(join(test2WorkspaceDir, 'AGENTS.md'), '# test2', 'utf8');

    const infoSpy = vi.spyOn(console, 'info').mockImplementation(() => {});
    const { deleteAgentConfig } = await import('@electron/utils/agent-config');

    const { snapshot } = await deleteAgentConfig('test2');

    expect(snapshot.agents.map((agent) => agent.id)).toEqual(['main', 'test3']);
    expect(snapshot.channelOwners.feishu).toBe('main');

    const config = await readOpenClawJson();
    expect((config.agents as { list: Array<{ id: string }> }).list.map((agent) => agent.id)).toEqual([
      'main',
      'test3',
    ]);
    expect(config.bindings).toEqual([]);
    await expect(access(test2RuntimeDir)).resolves.toBeUndefined();
    // Workspace deletion is intentionally deferred by `deleteAgentConfig` to avoid
    // ENOENT errors during Gateway restart, so it should still exist here.
    await expect(access(test2WorkspaceDir)).resolves.toBeUndefined();

    infoSpy.mockRestore();
  });

  it('preserves unmanaged custom workspaces when deleting an agent', async () => {
    const customWorkspaceDir = join(testHome, 'custom-workspace-test2');

    await writeOpenClawJson({
      agents: {
        list: [
          {
            id: 'main',
            name: 'Main',
            default: true,
            workspace: '~/.openclaw/workspace',
            agentDir: '~/.openclaw/agents/main/agent',
          },
          {
            id: 'test2',
            name: 'test2',
            workspace: customWorkspaceDir,
            agentDir: '~/.openclaw/agents/test2/agent',
          },
        ],
      },
    });

    await mkdir(join(testHome, '.openclaw', 'agents', 'test2', 'agent'), { recursive: true });
    await mkdir(customWorkspaceDir, { recursive: true });
    await writeFile(join(customWorkspaceDir, 'AGENTS.md'), '# custom', 'utf8');

    const warnSpy = vi.spyOn(console, 'warn').mockImplementation(() => {});
    const infoSpy = vi.spyOn(console, 'info').mockImplementation(() => {});
    const { deleteAgentConfig } = await import('@electron/utils/agent-config');

    await deleteAgentConfig('test2');

    await expect(access(customWorkspaceDir)).resolves.toBeUndefined();

    warnSpy.mockRestore();
    infoSpy.mockRestore();
  });

  it('persists persona, team role, and model when creating an agent profile and returns createdAgentId', async () => {
    await writeOpenClawJson({
      agents: {
        list: [
          {
            id: 'main',
            name: 'Main',
            default: true,
            workspace: '~/.openclaw/workspace',
            agentDir: '~/.openclaw/agents/main/agent',
          },
        ],
      },
    });

    await mkdir(join(testHome, '.openclaw', 'agents', 'main', 'agent'), { recursive: true });
    await mkdir(join(testHome, '.openclaw', 'workspace'), { recursive: true });
    await writeFile(join(testHome, '.openclaw', 'workspace', 'AGENTS.md'), '# Main', 'utf8');

    const { createAgent, listAgentsSnapshot, updateAgentProfile } = await import('@electron/utils/agent-config');

    const created = await createAgent({
      name: 'Research Helper',
      persona: 'Review code with a skeptical senior-engineer mindset.',
      teamRole: 'worker',
      model: 'openai/gpt-5.4',
    });
    expect(created.createdAgentId).toBe('research-helper');
    await updateAgentProfile('research-helper', {
      persona: 'Coordinate release readiness and keep reviews strict.',
      teamRole: 'worker',
      chatAccess: 'leader_only',
      responsibility: 'Research and evidence synthesis',
    });

    const snapshot = await listAgentsSnapshot();
    expect(snapshot.agents).toEqual(
      expect.arrayContaining([
        expect.objectContaining({
          id: 'research-helper',
          name: 'Research Helper',
          persona: 'Coordinate release readiness and keep reviews strict.',
          model: 'openai/gpt-5.4',
          modelDisplay: 'gpt-5.4',
          inheritedModel: false,
          teamRole: 'worker',
          chatAccess: 'leader_only',
          responsibility: 'Research and evidence synthesis',
        }),
      ]),
    );

    const config = await readOpenClawJson();
    expect((config.agents as { list: Array<{ id: string; persona?: string }> }).list).toEqual(
      expect.arrayContaining([
        expect.objectContaining({
          id: 'research-helper',
          persona: 'Coordinate release readiness and keep reviews strict.',
          model: 'openai/gpt-5.4',
          teamRole: 'worker',
          chatAccess: 'leader_only',
          responsibility: 'Research and evidence synthesis',
        }),
      ]),
    );
    expect(created.snapshot.agents).toEqual(
      expect.arrayContaining([
        expect.objectContaining({
          id: 'research-helper',
          persona: 'Review code with a skeptical senior-engineer mindset.',
          model: 'openai/gpt-5.4',
          teamRole: 'worker',
        }),
      ]),
    );
  });
});
import { beforeEach, describe, expect, it, vi } from 'vitest';
import { fireEvent, render, screen, waitFor } from '@testing-library/react';
import { MemoryRouter, Route, Routes } from 'react-router-dom';
import { AgentDetail } from '@/pages/AgentDetail';

const mockCronJobs = [
  {
    id: 'job-status-report',
    name: 'Status Report',
    message: 'Send a morning status update',
    schedule: '0 9 * * 1-5',
    sessionTarget: 'researcher',
    enabled: true,
    createdAt: '2026-01-01T08:00:00Z',
    updatedAt: '2026-02-01T08:00:00Z',
    lastRun: {
      time: '2026-03-24T08:00:00Z',
      success: true,
    },
  },
];

const { agentsStoreState, hostApiFetchMock } = vi.hoisted(() => ({
  agentsStoreState: {
    agents: [] as Array<{
      id: string;
      name: string;
      persona: string;
      isDefault: boolean;
      model: string;
      modelDisplay: string;
      inheritedModel: boolean;
      workspace: string;
      agentDir: string;
      mainSessionKey: string;
      channelTypes: string[];
      teamRole?: 'leader' | 'worker';
      chatAccess?: 'direct' | 'leader_only';
      responsibility?: string;
      reportsTo?: string | null;
      directReports?: string[];
    }>,
    loading: false,
    error: null as string | null,
    fetchAgents: vi.fn(async () => undefined),
    updateAgent: vi.fn(async () => undefined),
  },
  hostApiFetchMock: vi.fn(),
}));

vi.mock('@/stores/agents', () => ({
  useAgentsStore: () => agentsStoreState,
}));

vi.mock('@/lib/host-api', () => ({
  hostApiFetch: hostApiFetchMock,
}));

vi.mock('react-i18next', () => ({
  useTranslation: () => ({
    t: (_key: string, options?: string | { defaultValue?: string; [key: string]: unknown }) => {
      if (typeof options === 'string') return options;
      return options?.defaultValue ?? _key;
    },
  }),
}));

describe('AgentDetail page', () => {
  beforeEach(() => {
    vi.clearAllMocks();
    hostApiFetchMock.mockImplementation(async (path: string) => {
      if (path.includes('/workspace/skills')) {
        return { success: true, skills: [] };
      }
      if (path === '/api/agents/researcher/cron-relations') {
        return {
          relations: [
            {
              relationReason: 'session-target',
              deepLink: '/cron?jobId=job-status-report&agentId=researcher&tab=pipelines',
              job: mockCronJobs[0],
            },
          ],
        };
      }
      if (path === '/api/agents/main/cron-relations') {
        return { relations: [] };
      }
      throw new Error(`Unexpected hostApiFetch path: ${path}`);
    });

    agentsStoreState.loading = false;
    agentsStoreState.error = null;
    agentsStoreState.agents = [
      {
        id: 'main',
        name: 'Main',
        persona: 'Primary coordinator',
        isDefault: true,
        model: 'gpt-5.4',
        modelDisplay: 'GPT-5.4',
        inheritedModel: false,
        workspace: '~/.openclaw/workspace',
        agentDir: '~/.openclaw/agents/main',
        mainSessionKey: 'agent:main:main',
        channelTypes: ['feishu'],
        teamRole: 'leader',
        chatAccess: 'direct',
        responsibility: 'Coordinate the team',
        reportsTo: null,
        directReports: ['researcher'],
      },
      {
        id: 'researcher',
        name: 'Researcher',
        persona: 'Finds supporting evidence',
        isDefault: false,
        model: 'claude-sonnet-4',
        modelDisplay: 'Claude Sonnet 4',
        inheritedModel: true,
        workspace: '~/.openclaw/workspace-researcher',
        agentDir: '~/.openclaw/agents/researcher',
        mainSessionKey: 'agent:researcher:main',
        channelTypes: ['telegram', 'discord'],
        teamRole: 'worker',
        chatAccess: 'leader_only',
        responsibility: 'Research and evidence synthesis',
        reportsTo: 'main',
        directReports: [],
      },
    ];
  });

  it('renders read-only metadata and derived hierarchy for an agent', async () => {
    render(
      <MemoryRouter initialEntries={['/agents/researcher']}>
        <Routes>
          <Route path="/agents/:agentId" element={<AgentDetail />} />
        </Routes>
      </MemoryRouter>,
    );

    await waitFor(() => {
      expect(agentsStoreState.fetchAgents).toHaveBeenCalled();
    });

    expect(screen.getByRole('heading', { name: 'Researcher' })).toBeInTheDocument();
    expect(screen.getByText('Finds supporting evidence')).toBeInTheDocument();
    expect(screen.getByText('researcher')).toBeInTheDocument();
    expect(screen.getAllByText('Claude Sonnet 4').length).toBeGreaterThan(0);
    expect(screen.getAllByText('main').length).toBeGreaterThan(0);
    expect(screen.getByText('Researcher reports to Main')).toBeInTheDocument();
    expect(screen.getByText('telegram')).toBeInTheDocument();
    expect(screen.getByText('discord')).toBeInTheDocument();
    expect(screen.getByDisplayValue('worker')).toBeInTheDocument();
    expect(screen.getByDisplayValue('leader_only')).toBeInTheDocument();
    expect(screen.getByDisplayValue('Research and evidence synthesis')).toBeInTheDocument();
    expect(
      screen.getByText('This agent is blocked from normal direct chat and should be contacted through its leader.'),
    ).toBeInTheDocument();

    fireEvent.click(screen.getByRole('tab', { name: 'Activity' }));

    await waitFor(() => {
      expect(hostApiFetchMock).toHaveBeenCalledWith('/api/agents/researcher/cron-relations');
    });
    expect(await screen.findByText('Status Report')).toBeInTheDocument();
    expect(screen.getByText('0 9 * * 1-5')).toBeInTheDocument();
    expect(screen.getByText('session-target')).toBeInTheDocument();
  });

  it('shows a not-found state for unknown agents', async () => {
    render(
      <MemoryRouter initialEntries={['/agents/ghost']}>
        <Routes>
          <Route path="/agents/:agentId" element={<AgentDetail />} />
        </Routes>
      </MemoryRouter>,
    );

    await waitFor(() => {
      expect(agentsStoreState.fetchAgents).toHaveBeenCalled();
    });

    expect(screen.getByRole('heading', { name: 'Agent not found' })).toBeInTheDocument();
    expect(screen.getByRole('link', { name: 'Back to agents' })).toHaveAttribute('href', '/agents');
  });

  it('saves editable team configuration through the agents store', async () => {
    render(
      <MemoryRouter initialEntries={['/agents/researcher']}>
        <Routes>
          <Route path="/agents/:agentId" element={<AgentDetail />} />
        </Routes>
      </MemoryRouter>,
    );

    await waitFor(() => {
      expect(agentsStoreState.fetchAgents).toHaveBeenCalled();
    });

    fireEvent.change(screen.getByLabelText('Team role'), { target: { value: 'leader' } });
    fireEvent.change(screen.getByLabelText('Chat access'), { target: { value: 'direct' } });
    fireEvent.change(screen.getByLabelText('Responsibility'), { target: { value: 'Lead investigations' } });
    fireEvent.change(screen.getByLabelText('Reports to'), { target: { value: 'main' } });
    fireEvent.click(screen.getByRole('button', { name: 'Save team settings' }));

    await waitFor(() => {
      expect(agentsStoreState.updateAgent).toHaveBeenCalledWith('researcher', {
        teamRole: 'leader',
        chatAccess: 'direct',
        responsibility: 'Lead investigations',
        reportsTo: 'main',
      });
    });
  });

  it('renders Skills section with skill buttons', async () => {
    hostApiFetchMock.mockImplementation(async (path: string) => {
      if (path.includes('/workspace/skills') && !path.match(/\/workspace\/skills\/[^/]+$/)) {
        return { success: true, skills: ['researcher', 'code-review'] };
      }
      if (path.includes('/cron-relations')) return { relations: [] };
      return { success: true };
    });

    render(
      <MemoryRouter initialEntries={['/agents/main']}>
        <Routes>
          <Route path="/agents/:agentId" element={<AgentDetail />} />
        </Routes>
      </MemoryRouter>,
    );

    await waitFor(() => {
      expect(agentsStoreState.fetchAgents).toHaveBeenCalled();
    });

    fireEvent.click(screen.getByRole('tab', { name: 'Skills' }));

    // 'code-review' is only in the skills panel, so use it as anchor
    expect(await screen.findByText('code-review')).toBeInTheDocument();
    // 'researcher' appears as skill chip button (role="button")
    const skillButtons = screen.getAllByRole('button', { name: 'researcher' });
    expect(skillButtons.length).toBeGreaterThan(0);
  });

  it('shows empty state when no skills', async () => {
    hostApiFetchMock.mockImplementation(async (path: string) => {
      if (path.includes('/workspace/skills')) return { success: true, skills: [] };
      if (path.includes('/cron-relations')) return { relations: [] };
      return { success: true };
    });

    render(
      <MemoryRouter initialEntries={['/agents/main']}>
        <Routes>
          <Route path="/agents/:agentId" element={<AgentDetail />} />
        </Routes>
      </MemoryRouter>,
    );

    await waitFor(() => {
      expect(agentsStoreState.fetchAgents).toHaveBeenCalled();
    });

    fireEvent.click(screen.getByRole('tab', { name: 'Skills' }));

    expect(await screen.findByText('No skills configured.')).toBeInTheDocument();
  });
});
