import { describe, expect, it, vi } from 'vitest';
import { sendFeishuViaPreferredPath } from '@electron/utils/feishu-send-path';

describe('sendFeishuViaPreferredPath', () => {
  it('prefers direct plugin send before runtime send', async () => {
    const directSend = vi.fn(async () => ({
      messageId: 'om_direct_1',
      chatId: 'oc_direct_1',
    }));
    const runtimeSend = vi.fn(async () => ({
      sessionKey: 'agent:main:feishu:group:oc_direct_1',
      runId: 'run_fallback_1',
    }));

    const result = await sendFeishuViaPreferredPath({
      directSend,
      runtimeSend,
    });

    expect(directSend).toHaveBeenCalledTimes(1);
    expect(runtimeSend).not.toHaveBeenCalled();
    expect(result).toEqual({
      transport: 'direct',
      messageId: 'om_direct_1',
      chatId: 'oc_direct_1',
    });
  });

  it('falls back to runtime send when direct plugin send fails', async () => {
    const directSend = vi.fn(async () => {
      throw new Error('plugin unavailable');
    });
    const runtimeSend = vi.fn(async () => ({
      sessionKey: 'agent:main:feishu:group:oc_fallback_1',
      runId: 'run_fallback_1',
    }));

    const result = await sendFeishuViaPreferredPath({
      directSend,
      runtimeSend,
    });

    expect(directSend).toHaveBeenCalledTimes(1);
    expect(runtimeSend).toHaveBeenCalledTimes(1);
    expect(result).toEqual({
      transport: 'runtime',
      sessionKey: 'agent:main:feishu:group:oc_fallback_1',
      runId: 'run_fallback_1',
    });
  });
});
import { afterEach, beforeEach, describe, expect, it, vi } from 'vitest';
import { GatewayConnectionMonitor } from '@electron/gateway/connection-monitor';

describe('GatewayConnectionMonitor heartbeat', () => {
  beforeEach(() => {
    vi.useFakeTimers();
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it('triggers heartbeat timeout after configured consecutive misses', () => {
    const monitor = new GatewayConnectionMonitor();
    const sendPing = vi.fn();
    const onHeartbeatTimeout = vi.fn();

    monitor.startPing({
      sendPing,
      onHeartbeatTimeout,
      intervalMs: 100,
      timeoutMs: 40,
      maxConsecutiveMisses: 2,
    });

    vi.advanceTimersByTime(100);
    vi.advanceTimersByTime(100);
    vi.advanceTimersByTime(100);

    expect(sendPing).toHaveBeenCalledTimes(2);
    expect(onHeartbeatTimeout).toHaveBeenCalledTimes(1);
    expect(onHeartbeatTimeout).toHaveBeenCalledWith({
      consecutiveMisses: 2,
      timeoutMs: 40,
    });
  });

  it('resets heartbeat miss counter when alive is observed', () => {
    const monitor = new GatewayConnectionMonitor();
    const onHeartbeatTimeout = vi.fn();

    monitor.startPing({
      sendPing: vi.fn(),
      onHeartbeatTimeout,
      intervalMs: 100,
      timeoutMs: 40,
      maxConsecutiveMisses: 4,
    });

    vi.advanceTimersByTime(200);
    expect(monitor.getConsecutiveMisses()).toBe(1);

    monitor.markAlive('pong');
    expect(monitor.getConsecutiveMisses()).toBe(0);

    monitor.handlePong();
    expect(monitor.getConsecutiveMisses()).toBe(0);
    expect(onHeartbeatTimeout).not.toHaveBeenCalled();
  });
});
