// @vitest-environment node

import { existsSync, mkdirSync, mkdtempSync, rmSync } from 'node:fs';
import { join, resolve } from 'node:path';
import { readFileSync } from 'node:fs';
import { tmpdir } from 'node:os';
import { describe, expect, it, vi } from 'vitest';

import {
  WINDOWS_DEV_CACHE_DIR_NAMES,
  applyWindowsStartupSwitches,
  clearDevChromiumCaches,
} from '@electron/main/startup-hardening';

describe('gateway startup hardening', () => {
  it('applies Windows Chromium stability switches before startup', () => {
    const appendSwitch = vi.fn();

    applyWindowsStartupSwitches({
      platform: 'win32',
      commandLine: { appendSwitch },
    });

    expect(appendSwitch).toHaveBeenCalledWith('disable-direct-composition');
    expect(appendSwitch).toHaveBeenCalledWith('disable-direct-composition-video-overlays');
  });

  it('does not apply Windows-specific switches on non-Windows platforms', () => {
    const appendSwitch = vi.fn();

    applyWindowsStartupSwitches({
      platform: 'darwin',
      commandLine: { appendSwitch },
    });

    expect(appendSwitch).not.toHaveBeenCalled();
  });

  it('clears dev Chromium cache directories on Windows', () => {
    const userDataDir = mkdtempSync(join(tmpdir(), 'ktclaw-startup-hardening-'));
    try {
      for (const dirName of WINDOWS_DEV_CACHE_DIR_NAMES) {
        mkdirSync(join(userDataDir, dirName), { recursive: true });
      }

      const removed = clearDevChromiumCaches({
        isPackaged: false,
        platform: 'win32',
        userDataDir,
      });

      expect(removed.sort()).toEqual([...WINDOWS_DEV_CACHE_DIR_NAMES].sort());
      for (const dirName of WINDOWS_DEV_CACHE_DIR_NAMES) {
        expect(existsSync(join(userDataDir, dirName))).toBe(false);
      }
    } finally {
      rmSync(userDataDir, { recursive: true, force: true });
    }
  });

  it('leaves Chromium caches untouched outside Windows dev mode', () => {
    const userDataDir = mkdtempSync(join(tmpdir(), 'ktclaw-startup-hardening-'));
    const cacheDir = join(userDataDir, 'Cache');
    mkdirSync(cacheDir, { recursive: true });

    try {
      expect(clearDevChromiumCaches({
        isPackaged: true,
        platform: 'win32',
        userDataDir,
      })).toEqual([]);
      expect(existsSync(cacheDir)).toBe(true);

      expect(clearDevChromiumCaches({
        isPackaged: false,
        platform: 'linux',
        userDataDir,
      })).toEqual([]);
      expect(existsSync(cacheDir)).toBe(true);
    } finally {
      rmSync(userDataDir, { recursive: true, force: true });
    }
  });

  it('invokes startup hardening before app readiness work begins', () => {
    const source = readFileSync(resolve(process.cwd(), 'electron/main/index.ts'), 'utf8');
    const switchIndex = source.indexOf('applyWindowsStartupSwitches({');
    const cacheIndex = source.indexOf('clearDevChromiumCaches({');
    const whenReadyIndex = source.indexOf('app.whenReady().then(() => {');

    expect(switchIndex).toBeGreaterThan(-1);
    expect(cacheIndex).toBeGreaterThan(-1);
    expect(whenReadyIndex).toBeGreaterThan(-1);
    expect(switchIndex).toBeLessThan(whenReadyIndex);
    expect(cacheIndex).toBeLessThan(whenReadyIndex);
  });
});
