describe('vite packaging config', () => {
  it('does not force React or markdown into separate vendor chunks that can cycle with the main vendor bundle', () => {
    const viteConfig = readFileSync(resolve(process.cwd(), 'vite.config.ts'), 'utf8');

    expect(viteConfig).not.toContain("return 'vendor-react'");
    expect(viteConfig).not.toContain("return 'vendor-markdown'");
  });

  it('uses externalized main-process dependencies during dev to avoid rebundling the whole Electron runtime graph', () => {
    const viteConfig = readFileSync(resolve(process.cwd(), 'vite.config.ts'), 'utf8');

    expect(viteConfig).toContain("function isMainProcessExternal");
    expect(viteConfig).toContain("command === 'serve'");
    expect(viteConfig).toContain('external: mainProcessExternal');
  });

  it('scopes electron main/preload watch input so renderer-only edits do not restart Electron', () => {
    const viteConfig = readFileSync(resolve(process.cwd(), 'vite.config.ts'), 'utf8');

    expect(viteConfig).toContain('const electronWatchScope');
    expect(viteConfig).toContain("include: ['electron/**', 'shared/**', 'src/types/**', 'vite.config.ts', 'package.json']");
    expect(viteConfig).toContain("exclude: ['dist/**', 'dist-electron/**', 'node_modules/**']");
    expect(viteConfig).toContain('watch: electronWatchScope');
  });

  it('uses a smaller multi-file Electron dev build and suppresses expected chunk warnings', () => {
    const viteConfig = readFileSync(resolve(process.cwd(), 'vite.config.ts'), 'utf8');

    expect(viteConfig).toContain("minify: 'esbuild'");
    expect(viteConfig).toContain('reportCompressedSize: false');
    expect(viteConfig).toContain("createElectronServeOutput('electron/main')");
    expect(viteConfig).toContain("createElectronServeOutput('electron/preload')");
    expect(viteConfig).toContain('shouldIgnoreElectronRollupWarning');
    expect(viteConfig).toContain('onwarn: handleElectronRollupWarning');
  });
});
